+package doodlin.greeting.common.common.apilock.aspect
+
+import doodlin.greeting.common.common.apilock.annotation.DistributedLock
+import doodlin.greeting.common.common.apilock.annotation.DistributedLockTarget
+import io.kotest.assertions.throwables.shouldThrow
+import io.kotest.core.spec.style.BehaviorSpec
+import io.kotest.matchers.shouldBe
+import io.mockk.clearAllMocks
+import io.mockk.every
+import io.mockk.mockk
+import io.mockk.verify
+import org.aspectj.lang.ProceedingJoinPoint
+import org.aspectj.lang.reflect.MethodSignature
+import org.redisson.api.RLock
+import org.redisson.api.RedissonClient
+import org.springframework.transaction.support.TransactionSynchronization
+import org.springframework.transaction.support.TransactionSynchronizationManager
+import java.util.concurrent.TimeUnit
+
+class DistributedLockAspectTest : BehaviorSpec({
+
+    val redissonClient = mockk<RedissonClient>()
+    val aspect = DistributedLockAspect(redissonClient)
+    val joinPoint = mockk<ProceedingJoinPoint>()
+    val signature = mockk<MethodSignature>()
+    val multiLock = mockk<RLock>()
+
+    fun setupMocks() {
+        clearAllMocks()
+        every { joinPoint.signature } returns signature
+        every { signature.parameterNames } returns arrayOf("id")
+        every { joinPoint.args } returns arrayOf(1)
+        every { redissonClient.getLock(any<String>()) } returns multiLock
+        every { redissonClient.getMultiLock(any()) } returns multiLock
+        every { multiLock.tryLock(any(), any(), any<TimeUnit>()) } returns true
+        every { multiLock.isHeldByCurrentThread } returns true
+        every { multiLock.unlock() } returns Unit
+        every { joinPoint.proceed() } returns "result"
+    }
+
+    fun cleanupSynchronization() {
+        if (TransactionSynchronizationManager.isSynchronizationActive()) {
+            TransactionSynchronizationManager.clearSynchronization()
+        }
+    }
+
+    Given("releaseAfterTransactionCommit = false (기본값)") {
+        When("메서드 실행이 성공하면") {
+            Then("즉시 락을 해제한다") {
+                setupMocks()
+                every { signature.method } returns TestLockTarget::class.java.getMethod("immediateRelease", Int::class.java)
+
+                val result = aspect.process(joinPoint)
+
+                result shouldBe "result"
+                verify(exactly = 1) { multiLock.unlock() }
+            }
+        }
+
+        When("메서드 실행 중 예외가 발생하면") {
+            Then("락을 해제하고 예외를 전파한다") {
+                setupMocks()
+                every { signature.method } returns TestLockTarget::class.java.getMethod("immediateRelease", Int::class.java)
+                every { joinPoint.proceed() } throws RuntimeException("error")
+
+                shouldThrow<RuntimeException> { aspect.process(joinPoint) }
+
+                verify(exactly = 1) { multiLock.unlock() }
+            }
+        }
+    }
+
+    Given("releaseAfterTransactionCommit = true") {
+        When("트랜잭션 동기화가 활성화된 상태에서 메서드가 성공하면") {
+            Then("메서드 완료 시점에는 락이 해제되지 않는다") {
+                setupMocks()
+                every { signature.method } returns TestLockTarget::class.java.getMethod("deferredRelease", Int::class.java)
+                TransactionSynchronizationManager.initSynchronization()
+
+                try {
+                    aspect.process(joinPoint)
+                    verify(exactly = 0) { multiLock.unlock() }
+                } finally {
+                    cleanupSynchronization()
+                }
+            }
+
+            Then("트랜잭션 커밋 후 afterCompletion에서 락이 해제된다") {
+                setupMocks()
+                every { signature.method } returns TestLockTarget::class.java.getMethod("deferredRelease", Int::class.java)
+                TransactionSynchronizationManager.initSynchronization()
+
+                try {
+                    aspect.process(joinPoint)
+
+                    TransactionSynchronizationManager.getSynchronizations().forEach {
+                        it.afterCompletion(TransactionSynchronization.STATUS_COMMITTED)
+                    }
+
+                    verify(exactly = 1) { multiLock.unlock() }
+                } finally {
+                    cleanupSynchronization()
+                }
+            }
+        }
+
+        When("트랜잭션이 롤백되면") {
+            Then("afterCompletion에서 락이 해제된다") {
+                setupMocks()
+                every { signature.method } returns TestLockTarget::class.java.getMethod("deferredRelease", Int::class.java)
+                TransactionSynchronizationManager.initSynchronization()
+
+                try {
+                    aspect.process(joinPoint)
+
+                    TransactionSynchronizationManager.getSynchronizations().forEach {
+                        it.afterCompletion(TransactionSynchronization.STATUS_ROLLED_BACK)
+                    }
+
+                    verify(exactly = 1) { multiLock.unlock() }
+                } finally {
+                    cleanupSynchronization()
+                }
+            }
+        }
+
+        When("메서드 실행 중 예외가 발생하면") {
+            Then("즉시 락을 해제한다") {
+                setupMocks()
+                every { signature.method } returns TestLockTarget::class.java.getMethod("deferredRelease", Int::class.java)
+                TransactionSynchronizationManager.initSynchronization()
+
+                try {
+                    every { joinPoint.proceed() } throws RuntimeException("error")
+
+                    shouldThrow<RuntimeException> { aspect.process(joinPoint) }
+
+                    verify(exactly = 1) { multiLock.unlock() }
+                } finally {
+                    cleanupSynchronization()
+                }
+            }
+        }
+
+        When("트랜잭션 동기화가 비활성화 상태이면") {
+            Then("즉시 락을 해제한다 (fallback)") {
+                setupMocks()
+                every { signature.method } returns TestLockTarget::class.java.getMethod("deferredRelease", Int::class.java)
+                cleanupSynchronization()
+
+                val result = aspect.process(joinPoint)
+
+                result shouldBe "result"
+                verify(exactly = 1) { multiLock.unlock() }
+            }
+        }
+    }
+
+    Given("락 획득 실패") {
+        When("지정된 시간 내에 락을 획득하지 못하면") {
+            Then("LockAcquisitionException이 발생한다") {
+                setupMocks()
+                every { signature.method } returns TestLockTarget::class.java.getMethod("immediateRelease", Int::class.java)
+                every { multiLock.tryLock(any(), any(), any<TimeUnit>()) } returns false
+
+                shouldThrow<LockAcquisitionException> { aspect.process(joinPoint) }
+            }
+        }
+
+        When("InterruptedException이 발생하면") {
+            Then("LockAcquisitionException으로 변환된다") {
+                setupMocks()
+                every { signature.method } returns TestLockTarget::class.java.getMethod("immediateRelease", Int::class.java)
+                every { multiLock.tryLock(any(), any(), any<TimeUnit>()) } throws InterruptedException()
+
+                shouldThrow<LockAcquisitionException> { aspect.process(joinPoint) }
+            }
+        }
+    }
+})
+
+@Suppress("unused", "EmptyFunctionBlock", "NoConsecutiveBlankLines")
+private class TestLockTarget {
+    @DistributedLock(
+        cacheName = "test",
+        targets = [DistributedLockTarget(key = "id", expression = "#id")],
+        releaseAfterTransactionCommit = false
+    )
+    fun immediateRelease(id: Int) {}
+
+    @DistributedLock(
+        cacheName = "test",
+        targets = [DistributedLockTarget(key = "id", expression = "#id")],
+        releaseAfterTransactionCommit = true
+    )
+    fun deferredRelease(id: Int) {}
+}

